import { MapContainer, TileLayer } from "react-leaflet";
import { useEffect, useState } from "react";
import PlaneMarker from "../components/PlaneMarker";
import FlightPath from "../components/FlightPath";
import "leaflet/dist/leaflet.css";
import "./Dashboard.css";

export default function Dashboard() {
  const start = [12.9716, 77.5946];
  const end = [19.076, 72.8777];

  const [progress, setProgress] = useState(0);
  const [position, setPosition] = useState(start);
  const [flightNo, setFlightNo] = useState("AI202");

  // Smooth animation loop
  useEffect(() => {
    const interval = setInterval(() => {
      setProgress((p) => (p >= 1 ? 0 : p + 0.002));
    }, 16);

    return () => clearInterval(interval);
  }, []);

  // Update position
  useEffect(() => {
    const lat = start[0] + (end[0] - start[0]) * progress;
    const lng = start[1] + (end[1] - start[1]) * progress;

    setPosition([lat, lng]);
  }, [progress]);

  return (
    <div className="dashboard">
      {/* UI PANEL */}
      <div className="panel">
        ✈️ Flight Tracker

        <input
          type="text"
          value={flightNo}
          onChange={(e) => setFlightNo(e.target.value)}
          placeholder="Enter Flight No"
        />

        <p>Tracking: {flightNo}</p>
      </div>

      {/* MAP */}
      <MapContainer center={position} zoom={5} className="map">
        <TileLayer url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png" />

        <PlaneMarker position={position} />
        <FlightPath start={start} end={end} />
      </MapContainer>
    </div>
  );
}
